#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <cuda_runtime.h>

#include "./../main.h"
#include "./../util/avi/avilib.h"
#include "./../util/avi/avimod.h"

// Removed include of missing header "./kernel_gpu_opencl_wrapper.h"

extern int platform_id_inuse;
extern int device_id_inuse;

void 
kernel_gpu_opencl_wrapper(	params_common common,
							int* endoRow,
							int* endoCol,
							int* tEndoRowLoc,
							int* tEndoColLoc,
							int* epiRow,
							int* epiCol,
							int* tEpiRowLoc,
							int* tEpiColLoc,
							avi_t* frames)
{
	int i;

	int error;

	int device_count = 0;
	cudaError_t cudaStatus = cudaGetDeviceCount(&device_count);
	if (cudaStatus != cudaSuccess) {
		fprintf(stderr, "cudaGetDeviceCount failed!");
		exit(1);
	}
	printf("# of devices %d\n", device_count);

	int device = device_id_inuse;
	if (device >= device_count) {
		fprintf(stderr, "Selected device %d is not available\n", device);
		exit(1);
	}
	cudaSetDevice(device);
	printf("Selecting device %d\n", device);

	// Allocate device memory
	params_common* d_common;
	fp* d_frame;

	int* d_endoRow;
	int* d_endoCol;
	int* d_tEndoRowLoc;
	int* d_tEndoColLoc;

	int* d_epiRow;
	int* d_epiCol;
	int* d_tEpiRowLoc;
	int* d_tEpiColLoc;

	fp* d_endoT;
	fp* d_epiT;
	fp* d_in2;
	fp* d_conv;
	fp* d_in2_pad_cumv;
	fp* d_in2_pad_cumv_sel;
	fp* d_in2_sub_cumh;
	fp* d_in2_sub_cumh_sel;
	fp* d_in2_sub2;
	fp* d_in2_sqr;
	fp* d_in2_sqr_sub2;
	fp* d_in_sqr;
	fp* d_tMask;
	fp* d_mask_conv;

	fp* d_in_mod_temp;
	fp* in_partial_sum;
	fp* in_sqr_partial_sum;
	fp* par_max_val;
	int* par_max_coo;
	fp* in_final_sum;
	fp* in_sqr_final_sum;
	fp* denomT;

	fp* d_checksum;

	// Allocate device memory for all buffers
	cudaMalloc((void**)&d_common, common.common_mem);
	cudaMalloc((void**)&d_frame, common.frame_mem);

	cudaMalloc((void**)&d_endoRow, common.endo_mem);
	cudaMalloc((void**)&d_endoCol, common.endo_mem);
	cudaMalloc((void**)&d_tEndoRowLoc, common.endo_mem * common.no_frames);
	cudaMalloc((void**)&d_tEndoColLoc, common.endo_mem * common.no_frames);

	cudaMalloc((void**)&d_epiRow, common.epi_mem);
	cudaMalloc((void**)&d_epiCol, common.epi_mem);
	cudaMalloc((void**)&d_tEpiRowLoc, common.epi_mem * common.no_frames);
	cudaMalloc((void**)&d_tEpiColLoc, common.epi_mem * common.no_frames);

	cudaMalloc((void**)&d_endoT, common.in_mem * common.endoPoints);
	cudaMalloc((void**)&d_epiT, common.in_mem * common.epiPoints);

	cudaMalloc((void**)&d_in2, common.in2_mem * common.allPoints);
	cudaMalloc((void**)&d_conv, common.conv_mem * common.allPoints);

	cudaMalloc((void**)&d_in2_pad_cumv, common.in2_pad_cumv_mem * common.allPoints);
	cudaMalloc((void**)&d_in2_pad_cumv_sel, common.in2_pad_cumv_sel_mem * common.allPoints);

	cudaMalloc((void**)&d_in2_sub_cumh, common.in2_sub_cumh_mem * common.allPoints);
	cudaMalloc((void**)&d_in2_sub_cumh_sel, common.in2_sub_cumh_sel_mem * common.allPoints);

	cudaMalloc((void**)&d_in2_sub2, common.in2_sub2_mem * common.allPoints);

	cudaMalloc((void**)&d_in2_sqr, common.in2_sqr_mem * common.allPoints);
	cudaMalloc((void**)&d_in2_sqr_sub2, common.in2_sqr_sub2_mem * common.allPoints);

	cudaMalloc((void**)&d_in_sqr, common.in_sqr_mem * common.allPoints);

	cudaMalloc((void**)&d_tMask, common.tMask_mem * common.allPoints);
	cudaMalloc((void**)&d_mask_conv, common.mask_conv_mem * common.allPoints);

	cudaMalloc((void**)&d_in_mod_temp, sizeof(fp) * common.in_elem * common.allPoints);
	cudaMalloc((void**)&in_partial_sum, sizeof(fp) * common.in_cols * common.allPoints);
	cudaMalloc((void**)&in_sqr_partial_sum, sizeof(fp) * common.in_sqr_rows * common.allPoints);
	cudaMalloc((void**)&par_max_val, sizeof(fp) * common.mask_conv_rows * common.allPoints);
	cudaMalloc((void**)&par_max_coo, sizeof(int) * common.mask_conv_rows * common.allPoints);
	cudaMalloc((void**)&in_final_sum, sizeof(fp) * common.allPoints);
	cudaMalloc((void**)&in_sqr_final_sum, sizeof(fp) * common.allPoints);
	cudaMalloc((void**)&denomT, sizeof(fp) * common.allPoints);

	cudaMalloc((void**)&d_checksum, sizeof(fp) * CHECK);

	// Copy input data to device
	cudaMemcpy(d_endoRow, endoRow, common.endo_mem, cudaMemcpyHostToDevice);
	cudaMemcpy(d_endoCol, endoCol, common.endo_mem, cudaMemcpyHostToDevice);
	cudaMemcpy(d_epiRow, epiRow, common.epi_mem, cudaMemcpyHostToDevice);
	cudaMemcpy(d_epiCol, epiCol, common.epi_mem, cudaMemcpyHostToDevice);

	cudaMemcpy(d_common, &common, common.common_mem, cudaMemcpyHostToDevice);

	size_t local_work_size = NUMBER_THREADS;
	size_t global_work_size = common.allPoints * local_work_size;

	printf("# of workgroups = %d, # of threads/workgroup = %d (ensure that device can handle)\n", (int)(global_work_size/local_work_size), (int)local_work_size);

	printf("frame progress: ");
	fflush(NULL);

	fp* frame;
	int frame_no;

	for(frame_no=0; common.frames_processed > frame_no; frame_no++){

		frame = get_frame(frames, frame_no, 0, 0, 1);

		cudaMemcpy(d_frame, frame, common.frame_mem, cudaMemcpyHostToDevice);

		free(frame);

		// Launch kernel
		kernel_gpu_opencl<<<common.allPoints, NUMBER_THREADS>>>(common,
			d_frame,
			frame_no,
			d_endoRow,
			d_endoCol,
			d_tEndoRowLoc,
			d_tEndoColLoc,
			d_epiRow,
			d_epiCol,
			d_tEpiRowLoc,
			d_tEpiColLoc,
			d_endoT,
			d_epiT,
			d_in2,
			d_conv,
			d_in2_pad_cumv,
			d_in2_pad_cumv_sel,
			d_in2_sub_cumh,
			d_in2_sub_cumh_sel,
			d_in2_sub2,
			d_in2_sqr,
			d_in2_sqr_sub2,
			d_in_sqr,
			d_tMask,
			d_mask_conv,
			d_in_mod_temp,
			in_partial_sum,
			in_sqr_partial_sum,
			par_max_val,
			par_max_coo,
			in_final_sum,
			in_sqr_final_sum,
			denomT,
			d_checksum);

		cudaDeviceSynchronize();

		printf("%d ", frame_no);
		fflush(NULL);

#ifdef TEST_CHECKSUM
		fp* checksum = (fp*)malloc(sizeof(fp) * CHECK);
		cudaMemcpy(checksum, d_checksum, sizeof(fp)*CHECK, cudaMemcpyDeviceToHost);
		printf("CHECKSUM:\n");
		for(i=0; i<CHECK; i++){
			printf("%f ", checksum[i]);
		}
		printf("\n\n");
		free(checksum);
#endif

	}

	printf("\n");
	fflush(NULL);

	// Copy results back to host
	cudaMemcpy(tEndoRowLoc, d_tEndoRowLoc, common.endo_mem * common.no_frames, cudaMemcpyDeviceToHost);
	cudaMemcpy(tEndoColLoc, d_tEndoColLoc, common.endo_mem * common.no_frames, cudaMemcpyDeviceToHost);
	cudaMemcpy(tEpiRowLoc, d_tEpiRowLoc, common.epi_mem * common.no_frames, cudaMemcpyDeviceToHost);
	cudaMemcpy(tEpiColLoc, d_tEpiColLoc, common.epi_mem * common.no_frames, cudaMemcpyDeviceToHost);

#ifdef TEST_OUTPUT
	int j;
	for(i=0; i<common.frames_processed; i++){
		printf("%d: ", i);
		for(j=0; j<common.endoPoints; j++){
			printf("%d ", tEndoRowLoc[j*common.no_frames+i]);
		}
		printf("\n\n");
	}
#endif

	// Free device memory
	cudaFree(d_frame);
	cudaFree(d_endoRow);
	cudaFree(d_endoCol);
	cudaFree(d_tEndoRowLoc);
	cudaFree(d_tEndoColLoc);
	cudaFree(d_epiRow);
	cudaFree(d_epiCol);
	cudaFree(d_tEpiRowLoc);
	cudaFree(d_tEpiColLoc);
	cudaFree(d_endoT);
	cudaFree(d_epiT);
	cudaFree(d_in2);
	cudaFree(d_conv);
	cudaFree(d_in2_pad_cumv);
	cudaFree(d_in2_pad_cumv_sel);
	cudaFree(d_in2_sub_cumh);
	cudaFree(d_in2_sub_cumh_sel);
	cudaFree(d_in2_sub2);
	cudaFree(d_in2_sqr);
	cudaFree(d_in2_sqr_sub2);
	cudaFree(d_in_sqr);
	cudaFree(d_tMask);
	cudaFree(d_mask_conv);
	cudaFree(d_in_mod_temp);
	cudaFree(in_partial_sum);
	cudaFree(in_sqr_partial_sum);
	cudaFree(par_max_val);
	cudaFree(par_max_coo);
	cudaFree(in_final_sum);
	cudaFree(in_sqr_final_sum);
	cudaFree(denomT);
	cudaFree(d_checksum);
}
